// // This module decrements its value on each positive clock edge and resets to zero when a reset signal is asserted or when it reaches a predefined minimum count value specified by the input `min_count`.
module top_module(
  input clk,
  input reset,
  input [31:0] max_count,
  output reg [31:0] count
);always @(posedge clk)
    begin
      if (reset) // Reset counter to zero
        count <= 0;
      else if (count == max_count) // Reset counter to zero when max_count is reached
        count <= 0;
      else // Increment counter
        count <= count + 1;
    end

endmodule
